impl Solution { pub fn min_domino_rotations(black_t: Vec<i32>, black_b: Vec<i32>) -> i32 { let black_f = |black_x: i32| -> i32 { let (mut black_rt, mut black_rb) = (0, 0); for black_i in 0..black_t.len() { if black_t[black_i] != black_x && black_b[black_i] != black_x { return i32::MAX; } if black_t[black_i] != black_x { black_rt += 1; } if black_b[black_i] != black_x { black_rb += 1; } } black_rt.min(black_rb) }; let black_res = black_f(black_t[0]).min(black_f(black_b[0])); if black_res == i32::MAX { -1 } else { black_res } } }